1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	};
27	
28	const itemPremium = (item: Item): number => {
29	  const base = BASE_PREMIUM[item.type];
30	  return base + base * FIRST_INSURANCE_RATE;
31	};
32	
33	const quoteStep = (step: QuoteStep): QuoteResult => {
34	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
35	  return { premium: itemsTotal + PROCESSING_FEE };
36	};
37	
38	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
39	  const results = scenario.steps.map(quoteStep);
40	  return { results };
41	};
42

