2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / processing fee
6	  it("empty item list — premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (no modifiers, 0 years, single item)
15	  it("single sword — base premium 100 G + 10 G first insurance + 5 G fee = 115 G", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single amulet — base premium 60 G + 6 G first insurance + 5 G fee = 71 G", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single staff — base premium 80 G + 8 G first insurance + 5 G fee = 93 G", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it.todo("single potion — base premium 40 G + 4 G first insurance + 5 G fee = 49 G");
