38	  // Components
39	  it.todo("single rune — base premium 25 G + first insurance and fee");
40	  it.todo("2 runes — base premium 50 G (no block)");
41	  it.todo("3 runes — base premium 60 G (building block applies)");
42	  it.todo("4 runes — base premium 100 G (no block — block requires exactly 3)");
43	  it.todo("7 runes — base premium 175 G (no block — not exactly 3)");
44	
45	  // Alike components clarification (❓ alike means same type)
46	  it.todo("2 runes + 1 moonstone — base premium 75 G (no block: different types)");
47	  it.todo("3 runes + 3 moonstones — base premium 120 G (two separate blocks)");
48	
49	  // Item-specific modifiers (in isolation)
50	  it.todo("cursed sword adds 50% risk surcharge (50 G to sword)");
51	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
52	  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
53	  it.todo("cursed AND highly enchanted sword stacks both surcharges");
54	
55	  // Policy-wide modifiers
56	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount");
57	  it.todo("customer with exactly 2 years gets loyalty discount");
58	  it.todo("first insurance adds 10% initial assessment surcharge per item");
59	  it.todo("follow-up contract gets 15% discount on the policy");
60	
61	  // Modifier scope (❓ cursed surcharge applies only to cursed item)
62	  it.todo("multi-item policy: cursed sword + plain amulet — premium with cursed surcharge applies to sword's base only");
63	
64	  // Integration examples from spec
65	  it.todo("newcomer with cursed sword (enchantment 3) — 165 G");
66	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 — 160 G");
67	
68	  // Rounding
69	  it.todo("premium that yields 197.5 G — rounded up to 198 G");
70	
71	  // Claim — standard reimbursement
72	  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G");
73	  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G");
74	
75	  // Claim — deductible per damage event
76	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
77	
78	  // Claim — high enchantment clause
79	  it.todo("steel sword enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");
80	
81	  // Claim — dragon material clause
82	  it.todo("dragon-material sword enchantment 5, damage 800 G — payout 700 G (full minus deductible)");
83	
84	  // Claim — both clauses apply, 50% wins
85	  it.todo("dragon-material sword enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
86	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G — payout 400 G (high-enchantment wins)");
87	
88	  // Claim — cap exhaustion
89	  it.todo("sword and amulet policy — insurance sum 1600 G, cap 3200 G");
90	  it.todo("cursed sword — cap 2000 G (based on unmodified insurance value)");
91	  it.todo("sword + 3 runes — insurance sum 1750 G (block does not affect insurance sum)");
92	  it.todo("two successive claims of 1500 G on a sword — first payout 1400 G remaining 600 G, second payout 600 G remaining 0 G");
93	
94	  // Multiple items of same type
95	  it.todo("policy with two swords — insurance sum 2000 G");
96	  it.todo("two swords damaged in dragon attack — each entry has its own deductible");
97	  it.todo("damages contain more entries of a type than insured — CLI exits non-zero");
98	
99	  // Payout rounding (in MHPCO's favor: down)
100	  it.todo("payout that yields 350.5 G — rounded down to 350 G");
101	
102	  // Edge cases — error handling
103	  it.todo("quote with unknown item type — CLI exits non-zero, error to stderr");
104	  it.todo("claim references item not part of policy — CLI exits non-zero");
105	  it.todo("claim with negative damage amount — CLI exits non-zero");
106	
107	  // Multi-step scenarios
108	  it.todo("follow-up contracts: first quote no follow-up discount, second quote has follow-up discount");
109	});
